import{_ as i,o as a,c as t,af as e}from"./chunks/framework.BvYvR_Rg.js";const c=JSON.parse('{"title":"ESXi 7.x 安装到U盘","description":"","frontmatter":{"title":"ESXi 7.x 安装到U盘","date":"2022-10-09T19:51:53.000Z","category":"ESXi","tags":["ESXi"]},"headers":[],"relativePath":"posts/ESXi 7.x 安装到U盘.md","filePath":"posts/ESXi 7.x 安装到U盘.md","lastUpdated":1783008259000}'),p={name:"posts/ESXi 7.x 安装到U盘.md"};function h(n,s,l,k,d,o){return a(),t("div",null,[...s[0]||(s[0]=[e(`<h1 id="_0x01-背景" tabindex="-1">0x01 背景 <a class="header-anchor" href="#_0x01-背景" aria-label="Permalink to &quot;0x01 背景&quot;">​</a></h1><p>R86S刚出来时候还是很火的，各路网友吹爆，就跟风买了个万兆版，然后发现很鸡肋，万兆网卡太烂，远不如我的M920X+X520，定制挡板美滋滋。性能拉胯，N5105热得一批。体积小是唯一优点，但M920X也不大。</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/ESXi%E5%AE%89%E8%A3%85%E5%88%B0U%E7%9B%98/1669463836772.png" alt="R86S"></p><p>至于软件，万兆版本没有NVME接口，板载EMMC没法装ESXi，PVE用的少，虚拟机模板不多，而且sr-iov配置很坑，最终决定在U盘或者TF卡上装一个ESXi试试。</p><h1 id="_0x02-esxi-7-x-不建议安装到tf卡或者u盘" tabindex="-1">0x02 ESXi 7.x 不建议安装到TF卡或者U盘 <a class="header-anchor" href="#_0x02-esxi-7-x-不建议安装到tf卡或者u盘" aria-label="Permalink to &quot;0x02 ESXi 7.x 不建议安装到TF卡或者U盘&quot;">​</a></h1><p>在ESXi 5.x和6.x时代，将ESXi安装在U盘或者TF卡上非常常见，当年HP Gen8上的tf卡槽，还有很多服务器上的tf卡槽，给esxi用太配了。</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/ESXi%E5%AE%89%E8%A3%85%E5%88%B0U%E7%9B%98/1669464236640.png" alt="HP Gen8主板上的TF卡槽"> 但到了ESXi 7.x时代，官方也说了原因：<a href="https://kb.vmware.com/s/article/85685" target="_blank" rel="noreferrer">https://kb.vmware.com/s/article/85685</a> 因为系统机制的改变，会高频读写，TF卡的性能和寿命不足以支持，所以，别说TF卡，用QLC或者TLC的SSD都有可能会凉！这也是很多人在SSD上装ESXi跑一段时间后，写入量非常大，远比跑Win/Linux系统的日常使用写入大。</p><p>大概率是VMFSL的问题，这个虚拟分区就类似Linux的SWAP分区一样，做缓存写入量当然大。</p><p>不过我还是打算用U盘装一下试试。</p><h1 id="_0x03-esxi-7-x-安装到u盘" tabindex="-1">0x03 ESXi 7.x 安装到U盘 <a class="header-anchor" href="#_0x03-esxi-7-x-安装到u盘" aria-label="Permalink to &quot;0x03 ESXi 7.x 安装到U盘&quot;">​</a></h1><p>我用的是SanDisk的256G U盘，在安装ESXi的时候，引导后，按<code>Shift+O</code>键。 进入命令行后，在<code>runweasel cdromBoot</code>后输入<code>autoPartitionOSDataSize=4096</code>，然后按回车执行后续正常安装步骤，和安装到硬盘的方法一样，ESXi 7.x 可以直接安装到U盘，但在磁盘分区看不到磁盘，还是需要进行一些处理的。</p><p>装完后，先看看VMFSL的设置没有生效 <img src="https://raw.githubusercontent.com/white-alone/blog_img/master/ESXi%E5%AE%89%E8%A3%85%E5%88%B0U%E7%9B%98/1669465475504.png" alt="VMFSL设置"></p><p>安装完成后，打开SSH，关掉USB服务。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/etc/init.d/usbarbitrator</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stop</span></span></code></pre></div><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/ESXi%E5%AE%89%E8%A3%85%E5%88%B0U%E7%9B%98/1669465541426.png" alt="关闭USB服务"></p><p>用<code>partedUtil</code>看下分区表，可以和web上看到的分区表对应上</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/disks/</span></span></code></pre></div><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">partedUtil</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> getptbl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/disks/mpx.vmhba32</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">C0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">T0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">L0</span></span></code></pre></div><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/ESXi%E5%AE%89%E8%A3%85%E5%88%B0U%E7%9B%98/1669465577710.png" alt="查看分区表"> 用<code>partedUtil</code>调整<code>VMFSL</code>分区大小为4G，其实就是设置<code>VMFSL</code>的起始扇区和结束扇区，同时可以看到整个磁盘分区表结束扇区是<code>500170718</code>，记下这个数值。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">4G</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1024*1024*1024*4/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">512</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">8388608</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">16986112+8388608-1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=25374719</span></span></code></pre></div><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">partedUtil</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> resize</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;/dev/disks/mpx.vmhba32:C0:T0:L0&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 7</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 16986112</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 25374719</span></span></code></pre></div><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/ESXi%E5%AE%89%E8%A3%85%E5%88%B0U%E7%9B%98/1669465815513.png" alt="调整分区大小"></p><p>调整完成后，可以看到web页面的分区表也变了，<code>VMFSL</code>分区已经设置成4G</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/ESXi%E5%AE%89%E8%A3%85%E5%88%B0U%E7%9B%98/1669465850672.png" alt="调整后的分区表"></p><p>之后在分区表新增<code>VMFS</code>分区，分区间隔可以看到分区<code>5</code>的结束扇区和<code>6</code>的起始扇区，<code>6</code>的结束扇区和<code>7</code>的起始扇区，都是<code>2049=8597504-8595455=16986112-16984063</code>，所以新建的<code>VMFS </code>分区编号是<code>8</code>，起始扇区是<code>25374719+2049=25376768</code>，结束扇区是之前看到的<code>500170718</code>，UUID设置为<code>AA31E02A400F11DB9590000C2911D1B8 </code></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">partedUtil</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> setptbl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;/dev/disks/mpx.vmhba32:C0:T0:L0&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gpt</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;1 64 204863 C12A7328F81F11D2BA4B00A0C93EC93B 128&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;5 208896 8595455 EBD0A0A2B9E5443387C068B6B72699C7 0&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;6 8597504 16984063 EBD0A0A2B9E5443387C068B6B72699C7 0&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;7 16986112 25374719 4EB2EA3978554790A79EFAE495E21F8D 0&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;8 25376768 500170718 AA31E02A400F11DB9590000C2911D1B8 0&quot;</span></span></code></pre></div><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">partedUtil</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> getptbl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/disks/mpx.vmhba32</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">C0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">T0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">L0</span></span></code></pre></div><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/ESXi%E5%AE%89%E8%A3%85%E5%88%B0U%E7%9B%98/1669465886112.png" alt="新增VMFS分区"><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/ESXi%E5%AE%89%E8%A3%85%E5%88%B0U%E7%9B%98/1669466003876.png" alt="查看分区信息"></p><p>创建数据存储</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/sbin/vmkfstools</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -C</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vmfs6</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -b</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 1m</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> UDisk</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /vmfs/devices/disks/mpx.vmhba32</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">C0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">T0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">L0:8</span></span></code></pre></div><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/ESXi%E5%AE%89%E8%A3%85%E5%88%B0U%E7%9B%98/1669466047865.png" alt="创建数据存储"></p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/ESXi%E5%AE%89%E8%A3%85%E5%88%B0U%E7%9B%98/1669466066765.png" alt="数据存储"> 到这里就已经安装好了，可以在U盘上运行ESXi了，TF卡也是一样。</p><h1 id="_0x04-结语" tabindex="-1">0x04 结语 <a class="header-anchor" href="#_0x04-结语" aria-label="Permalink to &quot;0x04 结语&quot;">​</a></h1><p>不过还是不建议在U盘或者TF卡上跑ESXi 7.x，毕竟都不想一段时候后U盘或者TF卡凉凉了吧~~</p><p>当然，如果没有ESXi 7.x的刚需，用ESXi 6.x或者5.x，那就没问题了！</p>`,35)])])}const F=i(p,[["render",h]]);export{c as __pageData,F as default};
